(function () {
var widget = document.getElementById('ai-chatbot-widget');
if (!widget) return;
var chatUrl = widget.dataset.chatUrl;
var captureUrl = widget.dataset.captureUrl;
widget.innerHTML = '<button id="chatbot-toggle" aria-label="Open AI Chat" title="Chat with AI"><img alt="zeeframes" src="/frontend-assets/images/svgs/icon-with-yellow-bg.svg" width="28" height="28" style="cursor:pointer;"/></button>';
var inited = false;
function init() {
if (inited) return;
inited = true;
widget.innerHTML = [
'<button id="chatbot-toggle" aria-label="Open AI Chat" title="Chat with AI">',
'<img alt="zeeframes" src="/frontend-assets/images/svgs/icon-with-yellow-bg.svg" width="28" height="28" style="cursor:pointer;"/>',
'</button>',
'<div id="chatbot-box" aria-live="polite">',
'<div id="chatbot-sidebar">',
'<div id="chatbot-sidebar-header">',
'<span>Chats</span>',
'<button id="chatbot-sidebar-close" aria-label="Close sidebar">',
'<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">',
'<line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>',
'</svg>',
'</button>',
'</div>',
'<button id="chatbot-new-chat-btn">',
'<svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">',
'<line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>',
'</svg>',
' New Chat',
'</button>',
'<div id="chatbot-history-list"></div>',
'</div>',
'<div id="chatbot-main">',
'<div id="chatbot-header">',
'<div class="chatbot-header-left">',
'<button id="chatbot-sidebar-toggle" aria-label="Chat history">',
'<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">',
'<line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="18" x2="21" y2="18"/>',
'</svg>',
'</button>',
'<div class="chatbot-header-info">',
'<div class="chatbot-avatar">',
'<img alt="zeeframes" src="/frontend-assets/images/svgs/icon-with-yellow-bg.svg" width="28" height="28"/>',
'</div>',
'<div>',
'<p class="chatbot-name">Zaya - ZeeFrames AI</p>',
'<p class="chatbot-status">Online</p>',
'</div>',
'</div>',
'</div>',
'<button id="chatbot-close-btn" aria-label="Close chat">',
'<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">',
'<line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>',
'</svg>',
'</button>',
'</div>',
'<div id="chatbot-messages"></div>',
'<div id="chatbot-input-area">',
'<input type="text" id="chatbot-input" placeholder="Type a message..." autocomplete="off" />',
'<button id="chatbot-send" aria-label="Send message">',
'<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">',
'<line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/>',
'</svg>',
'</button>',
'</div>',
'</div>',
'</div>',
].join('');
var toggle = document.getElementById('chatbot-toggle');
var closeBtn = document.getElementById('chatbot-close-btn');
var input = document.getElementById('chatbot-input');
var sendBtn = document.getElementById('chatbot-send');
var messages = document.getElementById('chatbot-messages');
var sidebar = document.getElementById('chatbot-sidebar');
var sidebarToggle = document.getElementById('chatbot-sidebar-toggle');
var sidebarClose = document.getElementById('chatbot-sidebar-close');
var newChatBtn = document.getElementById('chatbot-new-chat-btn');
var historyList = document.getElementById('chatbot-history-list');
var csrfToken = document.querySelector('meta[name="csrf-token"]').getAttribute('content');
var sessions = [];
var activeId = null;
function createSession() {
var id = Date.now();
sessions.push({ id: id, label: 'New Chat', msgs: [] });
activeId = id;
widget.dataset.currentSession = String(id);
renderHistory();
clearMessages();
appendMessage("Hi there! 👋 I'm the ZeeFrames AI assistant. How can I help you today?", 'bot', true);
}
function getActive() {
return sessions.find(function (s) { return s.id === activeId; });
}
function renderHistory() {
historyList.innerHTML = '';
sessions.slice().reverse().forEach(function (s) {
var item = document.createElement('div');
item.className = 'chat-history-item' + (s.id === activeId ? ' active' : '');
item.textContent = s.label;
item.addEventListener('click', function () { loadSession(s.id); closeSidebar(); });
historyList.appendChild(item);
});
}
function loadSession(id) {
activeId = id;
widget.dataset.currentSession = String(id);
var s = getActive();
clearMessages();
s.msgs.forEach(function (m) { appendMessage(m.text, m.role, true); });
renderHistory();
}
function clearMessages() { messages.innerHTML = ''; }
function openChat() {
widget.classList.add('chat-open');
if (sessions.length === 0) createSession();
input.focus();
}
function closeChat() { widget.classList.remove('chat-open'); closeSidebar(); }
function openSidebar() { sidebar.classList.add('open'); }
function closeSidebar() { sidebar.classList.remove('open'); }
toggle.addEventListener('click', openChat);
closeBtn.addEventListener('click', closeChat);
sidebarToggle.addEventListener('click', function () {
sidebar.classList.contains('open') ? closeSidebar() : openSidebar();
});
sidebarClose.addEventListener('click', closeSidebar);
newChatBtn.addEventListener('click', function () { createSession(); closeSidebar(); });
function buildEmailForm() {
var wrap = document.createElement('div');
wrap.className = 'chatbot-email-form';
wrap.innerHTML =
'<input type="email" class="chatbot-email-input" placeholder="your@work.com" />' +
'<button class="chatbot-email-submit">Send</button>' +
'<p class="chatbot-email-note"></p>';
var emailInput = wrap.querySelector('.chatbot-email-input');
var submitBtn = wrap.querySelector('.chatbot-email-submit');
var note = wrap.querySelector('.chatbot-email-note');
submitBtn.addEventListener('click', function () {
var email = emailInput.value.trim();
if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
note.textContent = 'Please enter a valid email.';
note.style.color = '#f87171';
return;
}
submitBtn.disabled = true;
submitBtn.textContent = 'Sending…';
var s = getActive();
var context = (s ? s.msgs : []).slice(-6)
.map(function (m) { return (m.role === 'user' ? 'User' : 'Bot') + ': ' + m.text; })
.join('\n');
fetch(captureUrl, {
method: 'POST',
headers: { 'Content-Type': 'application/json', 'X-CSRF-TOKEN': csrfToken },
body: JSON.stringify({ email: email, context: context, session_key: widget.dataset.currentSession || null }),
})
.then(function (r) { return r.json(); })
.then(function () {
wrap.innerHTML = '<p class="chatbot-email-success">✅ Got it! Our team will reach out to <strong>' + email + '</strong> shortly.</p>';
})
.catch(function () {
note.textContent = 'Something went wrong. Please try again.';
note.style.color = '#f87171';
submitBtn.disabled = false;
submitBtn.textContent = 'Send';
});
});
emailInput.addEventListener('keydown', function (e) { if (e.key === 'Enter') submitBtn.click(); });
return wrap;
}
function appendMessage(text, role, silent) {
var cssClass = (role === 'model') ? 'bot' : role;
var storeRole = (role === 'bot') ? 'model' : role;
var div = document.createElement('div');
div.className = 'chat-msg ' + cssClass;
var p = document.createElement('p');
if (cssClass === 'bot') {
var hasEmailForm = text.includes('[COLLECT_EMAIL]');
var cleanText = text.replace(/\[COLLECT_EMAIL\]/g, '').trim();
var html = cleanText
.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
.replace(/\[([^\]]+)\]\((https?:\/\/[^\)]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>')
.replace(/(👉\s*)(https?:\/\/\S+)/g, '$1<a href="$2" target="_blank" rel="noopener">$2</a>')
.replace(/\n/g, '<br>');
p.innerHTML = html;
div.appendChild(p);
if (hasEmailForm && !silent) div.appendChild(buildEmailForm());
} else {
p.textContent = text;
div.appendChild(p);
}
messages.appendChild(div);
messages.scrollTop = messages.scrollHeight;
if (!silent) {
var s = getActive();
if (s) {
s.msgs.push({ text: text, role: storeRole });
if (storeRole === 'user' && s.msgs.filter(function (m) { return m.role === 'user'; }).length === 1) {
s.label = text.length > 28 ? text.slice(0, 28) + '…' : text;
renderHistory();
}
}
}
return div;
}
function showTyping() {
var div = document.createElement('div');
div.className = 'chat-msg bot typing';
div.innerHTML = '<span></span><span></span><span></span>';
messages.appendChild(div);
messages.scrollTop = messages.scrollHeight;
return div;
}
function sendMessage() {
var text = input.value.trim();
if (!text) return;
appendMessage(text, 'user');
input.value = '';
sendBtn.disabled = true;
var typing = showTyping();
var s = getActive();
var history = (s ? s.msgs : [])
.filter(function (m) { return m.role === 'user' || m.role === 'model'; })
.slice(0, -1)
.map(function (m) { return { role: m.role, text: m.text }; });
fetch(chatUrl, {
method: 'POST',
headers: { 'Content-Type': 'application/json', 'X-CSRF-TOKEN': csrfToken },
body: JSON.stringify({ message: text, history: history, session_key: s ? String(s.id) : null, session_label: s ? s.label : null }),
})
.then(function (res) {
if (!res.ok || !res.body) throw new Error('stream_failed');
typing.remove();
var div = document.createElement('div');
div.className = 'chat-msg bot';
var p = document.createElement('p');
div.appendChild(p);
messages.appendChild(div);
var fullText = '';
var reader = res.body.getReader();
var decoder = new TextDecoder();
var buffer = '';
function read() {
reader.read().then(function (result) {
if (result.done) {
sendBtn.disabled = false;
var active = getActive();
if (active) {
active.msgs.push({ text: fullText, role: 'model' });
if (active.msgs.filter(function(m){ return m.role === 'user'; }).length === 1) {
active.label = fullText.length > 28 ? fullText.slice(0, 28) + '\u2026' : fullText;
renderHistory();
}
}
return;
}
buffer += decoder.decode(result.value, { stream: true });
var lines = buffer.split('\n');
buffer = lines.pop();
lines.forEach(function (line) {
line = line.trim();
if (!line.startsWith('data: ')) return;
var data = line.slice(6);
if (data === '[DONE]') return;
try {
var chunk = JSON.parse(data);
var token = chunk.token || '';
fullText += token;
p.innerHTML = fullText
.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
.replace(/\[([^\]]+)\]\((https?:\/\/[^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>')
.replace(/\n/g, '<br>');
messages.scrollTop = messages.scrollHeight;
} catch (e) {}
});
read();
});
}
read();
})
.catch(function () {
typing.remove();
sendBtn.disabled = false;
appendMessage('Something went wrong. Please try again.', 'bot');
});
}
sendBtn.addEventListener('click', sendMessage);
input.addEventListener('keydown', function (e) { if (e.key === 'Enter') sendMessage(); });
openChat();
}
document.getElementById('chatbot-toggle').addEventListener('click', function onFirstClick() {
document.getElementById('chatbot-toggle').removeEventListener('click', onFirstClick);
init();
});
})();